import{c as n,Q as r,j as a,m as t}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Harness Engineering 研究全景","description":"","frontmatter":{},"headers":[],"relativePath":"resources/research/harness-engineering.md","filePath":"resources/research/harness-engineering.md","lastUpdated":1779796674000}'),i={name:"resources/research/harness-engineering.md"};function o(s,e,l,g,h,d){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="harness-engineering-研究全景" tabindex="-1">Harness Engineering 研究全景 <a class="header-anchor" href="#harness-engineering-研究全景" aria-label="Permalink to &quot;Harness Engineering 研究全景&quot;">​</a></h1><p>整合 16 篇核心論文、工程博客資源與 Benchmark 數據，建立 Agent Harness Engineering 的知識基礎。</p><h2 id="priority-a-—-核心論文-必讀" tabindex="-1">Priority A — 核心論文（必讀） <a class="header-anchor" href="#priority-a-—-核心論文-必讀" aria-label="Permalink to &quot;Priority A — 核心論文（必讀）&quot;">​</a></h2><h3 id="_1-ahe-observability-driven-automatic-evolution" tabindex="-1">1. AHE: Observability-Driven Automatic Evolution <a class="header-anchor" href="#_1-ahe-observability-driven-automatic-evolution" aria-label="Permalink to &quot;1. AHE: Observability-Driven Automatic Evolution&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.25850" target="_blank" rel="noreferrer">2604.25850</a></li><li><strong>發表</strong>: 2026-04</li><li><strong>核心洞見</strong>: 提出 AHE 框架，透過三個可觀測性柱子（元件 / 經驗 / 決策）自動進化 agent harnesses。<strong>Harness 改進應由工具、中介軟體、長期記憶主導，而非系統提示詞。</strong></li><li><strong>關鍵成果</strong>: <ul><li>Terminal-Bench 2: pass@1 <strong>69.7% → 77.0%</strong>（10 次自動迭代）</li><li>SWE-bench-verified: 用 <strong>12% 更少 token</strong> 達最佳成績</li><li>跨模型族遷移收益：<strong>+5.1 到 +10.1 pp</strong></li></ul></li><li><strong>意義</strong>: 直接驗證「harness &gt; model」命題；Ratchet 自動化演進的學術支撐</li></ul><hr><h3 id="_2-building-ai-coding-agents-for-the-terminal" tabindex="-1">2. Building AI Coding Agents for the Terminal <a class="header-anchor" href="#_2-building-ai-coding-agents-for-the-terminal" aria-label="Permalink to &quot;2. Building AI Coding Agents for the Terminal&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.05344" target="_blank" rel="noreferrer">2603.05344</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>核心洞見</strong>: 首篇系統區分「Scaffolding（組裝期）」vs「Harness（執行期）」概念的論文。 <ul><li><strong>Scaffolding 定義</strong>: 系統提示、工具定義、subagent 註冊</li><li><strong>Harness 定義</strong>: 工具分派、context 管理、安全執行、session 持久化</li></ul></li><li><strong>架構創新</strong>: 工作負載專門化模型路由、懶惰工具發現、自動化記憶系統</li></ul><hr><h3 id="_3-inside-the-scaffold-a-source-code-taxonomy-of-coding-agent-architectures" tabindex="-1">3. Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures <a class="header-anchor" href="#_3-inside-the-scaffold-a-source-code-taxonomy-of-coding-agent-architectures" aria-label="Permalink to &quot;3. Inside the Scaffold: A Source-Code Taxonomy of Coding Agent Architectures&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2604.03515" target="_blank" rel="noreferrer">2604.03515</a></li><li><strong>發表</strong>: 2026-04</li><li><strong>核心洞見</strong>: 首次對 <strong>13 個開源 coding agents</strong> 進行源碼層級架構分析，提出跨 12 維度、3 層組織的統一分類學。</li><li><strong>5 個通用控制原語</strong>: <ol><li>ReAct（推理-行動交錯）</li><li>Generate-test-repair</li><li>Plan-execute</li><li>Multi-attempt retry</li><li>Tree search</li></ol></li><li><strong>關鍵發現</strong>: 11/13 agents 混合多個原語，而非單一模式</li></ul><hr><h3 id="_4-nlah-natural-language-agent-harnesses" tabindex="-1">4. NLAH: Natural-Language Agent Harnesses <a class="header-anchor" href="#_4-nlah-natural-language-agent-harnesses" aria-label="Permalink to &quot;4. NLAH: Natural-Language Agent Harnesses&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.25723" target="_blank" rel="noreferrer">2603.25723</a></li><li><strong>發表</strong>: 2026-03</li><li><strong>核心洞見</strong>: 提出用自然語言表達 harness 行為，引入 Natural-Language Agent Harnesses (NLAHs) 與 Intelligent Harness Runtime (IHR)。解決 harness「深埋在控制器代碼中」的可移植性問題。</li><li><strong>核心價值</strong>: 使 harness 設計可跨系統遷移、可對比、可科學研究</li></ul><hr><h3 id="_5-meta-harness-end-to-end-optimization" tabindex="-1">5. Meta-Harness: End-to-End Optimization <a class="header-anchor" href="#_5-meta-harness-end-to-end-optimization" aria-label="Permalink to &quot;5. Meta-Harness: End-to-End Optimization&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.28052" target="_blank" rel="noreferrer">2603.28052</a></li><li><strong>發表</strong>: 2026-03（Stanford/Chelsea Finn）</li><li><strong>核心洞見</strong>: 外層迴圈系統，透過訪問原始代碼、分數和所有先前執行軌跡，用 agent 搜尋 harness 代碼空間。類似 Neural Architecture Search，但針對 harness 層。</li><li><strong>關鍵成果</strong>: 聯合優化 harness + 模型的收益 <strong>15-22%</strong></li></ul><hr><h2 id="priority-b-—-重要論文" tabindex="-1">Priority B — 重要論文 <a class="header-anchor" href="#priority-b-—-重要論文" aria-label="Permalink to &quot;Priority B — 重要論文&quot;">​</a></h2><h3 id="_6-react-synergizing-reasoning-and-acting" tabindex="-1">6. ReAct: Synergizing Reasoning and Acting <a class="header-anchor" href="#_6-react-synergizing-reasoning-and-acting" aria-label="Permalink to &quot;6. ReAct: Synergizing Reasoning and Acting&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">2210.03629</a>（ICLR 2023）</li><li><strong>核心</strong>: LLM agent 的基礎論文。定義推理跡象（reasoning traces）與行動（actions）的交錯模式。</li><li><strong>成果</strong>: HotpotQA 超越 CoT；ALFWorld +34% 絕對成功率</li></ul><h3 id="_7-agent-harness-survey" tabindex="-1">7. Agent Harness Survey <a class="header-anchor" href="#_7-agent-harness-survey" aria-label="Permalink to &quot;7. Agent Harness Survey&quot;">​</a></h3><ul><li><strong>來源</strong>: Preprints.org, 2026-03</li><li><strong>核心引述</strong>: 「隨著 agent 任務變長變複雜，執行可靠性越來越不是模型能力問題，而是包裹在它周圍的『基礎設施層』——agent 執行 harness」</li></ul><h3 id="_8-memory-for-autonomous-llm-agents" tabindex="-1">8. Memory for Autonomous LLM Agents <a class="header-anchor" href="#_8-memory-for-autonomous-llm-agents" aria-label="Permalink to &quot;8. Memory for Autonomous LLM Agents&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.07670" target="_blank" rel="noreferrer">2603.07670</a></li><li><strong>核心</strong>: long-running agents 的記憶設計調查。Pattern B（主流）：working memory 在 context window，長期記錄在外部向量/結構化存儲，每步檢索相關記錄。</li><li><strong>核心挑戰</strong>: 檢索品質是瓶頸</li></ul><h3 id="_9-agentic-ai-architectures-taxonomies-and-evaluation" tabindex="-1">9. Agentic AI: Architectures, Taxonomies, and Evaluation <a class="header-anchor" href="#_9-agentic-ai-architectures-taxonomies-and-evaluation" aria-label="Permalink to &quot;9. Agentic AI: Architectures, Taxonomies, and Evaluation&quot;">​</a></h3><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2601.12560" target="_blank" rel="noreferrer">2601.12560</a></li><li><strong>核心</strong>: 新一代 LLM agents 作為結合記憶、工具使用、環境反饋的認知控制器。涵蓋 CAMEL、AutoGen、MetaGPT、LangGraph、Swarm 等框架。</li></ul><hr><h2 id="priority-c-—-工具與方法論論文" tabindex="-1">Priority C — 工具與方法論論文 <a class="header-anchor" href="#priority-c-—-工具與方法論論文" aria-label="Permalink to &quot;Priority C — 工具與方法論論文&quot;">​</a></h2><table tabindex="0"><thead><tr><th>論文</th><th>arXiv</th><th>核心貢獻</th></tr></thead><tbody><tr><td>Learning to Rewrite Tool Descriptions</td><td>2602.20426</td><td>工具描述的措辭顯著影響 agent 成功率；提出自動化重寫工具 schema</td></tr><tr><td>Act While Thinking</td><td>2603.18897</td><td>在 agent 完成思考前並行執行工具，減少延遲</td></tr><tr><td>Design Patterns for Securing LLM Agents</td><td>2506.08837</td><td>LLM agent 安全防禦模式，針對提示詞注入等攻擊</td></tr><tr><td>Architecting Resilient LLM Agents</td><td>2509.08646</td><td>安全的 Plan-and-Execute 架構設計</td></tr></tbody></table><hr><h2 id="工程博客資源" tabindex="-1">工程博客資源 <a class="header-anchor" href="#工程博客資源" aria-label="Permalink to &quot;工程博客資源&quot;">​</a></h2><h3 id="lilian-weng-—-llm-powered-autonomous-agents" tabindex="-1">Lilian Weng — LLM Powered Autonomous Agents <a class="header-anchor" href="#lilian-weng-—-llm-powered-autonomous-agents" aria-label="Permalink to &quot;Lilian Weng — LLM Powered Autonomous Agents&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://lilianweng.github.io/posts/2023-06-23-agent/" target="_blank" rel="noreferrer">lilianweng.github.io</a></li><li><strong>定位</strong>: 業界標準入門文章；Planning-Memory-Tools 三層框架的經典定義</li><li><strong>核心框架</strong>: <ul><li>Planning: Task Decomposition（CoT, ToT）+ Self-Reflection</li><li>Memory: Sensory / Short-term（context）/ Long-term（向量存儲）</li><li>Tools: 外部 API 超越訓練數據限制</li></ul></li></ul><h3 id="eugene-yan-—-patterns-for-building-llm-based-systems" tabindex="-1">Eugene Yan — Patterns for Building LLM-based Systems <a class="header-anchor" href="#eugene-yan-—-patterns-for-building-llm-based-systems" aria-label="Permalink to &quot;Eugene Yan — Patterns for Building LLM-based Systems&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://eugeneyan.com/writing/llm-patterns/" target="_blank" rel="noreferrer">eugeneyan.com</a></li><li><strong>7 大 Patterns</strong>: Evals、RAG、Fine-tuning、Caching、Guardrails、Defensive UX、Collect User Feedback</li><li><strong>Agent Harness 洞見</strong>: 「專化模型組隊」勝過單一通才；Guardrails + Evals 是生產環境必需品</li></ul><h3 id="adnan-masood-—-agent-harness-engineering-the-rise-of-the-ai-control-plane" tabindex="-1">Adnan Masood — Agent Harness Engineering: The Rise of the AI Control Plane <a class="header-anchor" href="#adnan-masood-—-agent-harness-engineering-the-rise-of-the-ai-control-plane" aria-label="Permalink to &quot;Adnan Masood — Agent Harness Engineering: The Rise of the AI Control Plane&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">Medium</a></li><li><strong>核心</strong>: 5 層 Control Plane 架構視角（Context → Tool/Function → Execution Loop → State &amp; Memory → Safety &amp; Observability）</li><li><strong>關鍵統計</strong>: 企業 AI 失敗 <strong>65% 源自 harness 層缺陷</strong>，而非模型限制</li><li><strong>獨特觀點</strong>: 正確 cache 管理可將 token 成本降低十倍</li></ul><h3 id="daily-dose-of-ds-—-the-anatomy-of-an-agent-harness" tabindex="-1">Daily Dose of DS — The Anatomy of an Agent Harness <a class="header-anchor" href="#daily-dose-of-ds-—-the-anatomy-of-an-agent-harness" aria-label="Permalink to &quot;Daily Dose of DS — The Anatomy of an Agent Harness&quot;">​</a></h3><ul><li><strong>定位</strong>: 最完整的 harness 組件分解（11 個生產級組件）</li><li><strong>11 個核心組件</strong>: Orchestration Loop、Tools、Memory、Context Management、Prompt Construction、Output Parsing、State Management、Error Handling、Guardrails &amp; Safety、Verification Loops、Subagent Orchestration</li><li><strong>核心論點</strong>: Verification 能使品質提升 2-3 倍</li></ul><h3 id="langchain-—-agent-engineering-a-new-discipline" tabindex="-1">LangChain — Agent Engineering: A New Discipline <a class="header-anchor" href="#langchain-—-agent-engineering-a-new-discipline" aria-label="Permalink to &quot;LangChain — Agent Engineering: A New Discipline&quot;">​</a></h3><ul><li><strong>核心定義</strong>: 「將非確定性 LLM 系統迭代精煉為可靠生產體驗的過程」</li><li><strong>工程循環</strong>: Build → Test → Ship → Observe → Refine → Repeat</li><li><strong>關鍵轉變</strong>: 放棄「發布前完美」，改為快速發行 + 生產學習</li></ul><hr><h2 id="benchmark-資源" tabindex="-1">Benchmark 資源 <a class="header-anchor" href="#benchmark-資源" aria-label="Permalink to &quot;Benchmark 資源&quot;">​</a></h2><h3 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://www.tbench.ai/leaderboard/terminal-bench/2.0" target="_blank" rel="noreferrer">tbench.ai</a></li><li><strong>Harness 影響量化</strong>: 同 Opus 4.6，不同 Harness：<strong>66.9% → 79.8%</strong>（13pp 差距）</li><li><strong>意義</strong>: 第一個直接量化 harness 影響的 benchmark</li></ul><h3 id="swe-bench-swe-bench-verified-swe-bench-pro" tabindex="-1">SWE-bench / SWE-bench Verified / SWE-bench Pro <a class="header-anchor" href="#swe-bench-swe-bench-verified-swe-bench-pro" aria-label="Permalink to &quot;SWE-bench / SWE-bench Verified / SWE-bench Pro&quot;">​</a></h3><ul><li><strong>URL</strong>: <a href="https://www.swebench.com/" target="_blank" rel="noreferrer">swebench.com</a></li><li><strong>規模</strong>: 2,294 issues；Verified 版 500 個（人工 3 倍驗證）</li><li><strong>2026 最新成績（SWE-bench Pro）</strong>: Claude Opus 4.7 64.3%、GPT-5.4 57.7%</li></ul><hr><h2 id="跨源共識點" tabindex="-1">跨源共識點 <a class="header-anchor" href="#跨源共識點" aria-label="Permalink to &quot;跨源共識點&quot;">​</a></h2><table tabindex="0"><thead><tr><th>共識</th><th>量化依據</th><th>核心論文</th></tr></thead><tbody><tr><td>Harness 影響 &gt; Model 大小</td><td>Vesper 論文：harness 結構佔 40% 性能差距，model 大小只佔 30%</td><td>2605.15221</td></tr><tr><td>Context 管理是最高槓桿</td><td>Stanford Meta-Harness：59.6% → 76.4%（16.8pp）</td><td>2603.28052</td></tr><tr><td>Verification 使品質提升 2-3×</td><td>Daily Dose DS；LangChain 從 Top 30 → Top 5</td><td>NLAH 論文</td></tr><tr><td>Harness 可不重訓練自動演化</td><td>Continual Harness：運行時在線 RL 循環</td><td>2605.09998</td></tr><tr><td>工具設計是 schema 語言工程</td><td>Tool Rewriting 論文：措辭顯著影響成功率</td><td>2602.20426</td></tr></tbody></table><hr><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><a href="/cc-workspace-docs/resources/research/knowledge-map/">跨源知識地圖</a></li><li><a href="/cc-workspace-docs/resources/reference/">延伸閱讀與參考資料</a></li><li><a href="/cc-workspace-docs/lectures/lecture-01-foundations/">Lecture 01：Claude Code 與 Harness 基礎</a></li></ul>',54)])])}const b=n(i,[["render",o]]);export{u as __pageData,b as default};
